39→
40→interface PerformCopyOptions {
41→  hudTitle?: string;
42→  hudIcon?: ReactNode;
43→  onCopy?: () => void;
44→}
45→
46→export function performCopy(
47→  content: string,
48→  showHUD: ShowHUD,
49→  options?: PerformCopyOptions,
50→): void {
51→  copyToClipboard(content).catch(() => {});
52→  showHUD({
53→    icon: options?.hudIcon ?? <CopyHUDIcon />,
54→    title: options?.hudTitle ?? 'Copied to Clipboard',
55→  });
56→  options?.onCopy?.();
57→}
58→
59→interface CreateCopyActionOptions {
60→  content: string;
61→  title?: string;
62→  hudTitle?: string;
63→  hudIcon?: ReactNode;
64→  shortcut?: ReactNode;
65→  onCopy?: () => void;
66→}
67→
68→export function createCopyAction(
69→  options: CreateCopyActionOptions,
70→  showHUD: ShowHUD,
71→): DropdownAction {
72→  return {
73→    label: options.title ?? 'Copy',
74→    shortcut: options.shortcut,
75→    onClick: () => {
76→      performCopy(options.content, showHUD, {
77→        hudTitle: options.hudTitle,
78→        hudIcon: options.hudIcon,
79→        onCopy: options.onCopy,
80→      });
81→    },
82→  };
83→}
