 1→import type { ReactNode } from 'react';
 2→import type { TagColor } from './constants/tag_colors';
 3→
 4→export interface ListItemData {
 5→  id: string;
 6→  title: string;
 7→  subtitle?: string;
 8→  icon?: ReactNode;
 9→  accessories?: ListItemAccessoryData[];
10→  detail?: ListItemDetailData;
11→}
12→
13→export interface ListItemAccessoryData {
14→  text?: string;
15→  icon?: ReactNode;
16→  date?: Date;
17→  tag?: {
18→    text: string;
19→    color?: TagColor;
20→  };
21→  tooltip?: string;
22→}
23→
24→export interface ListItemDetailData {
25→  markdown: string;
26→  metadata?: ListItemMetadataEntry[];
27→}
28→
29→export type ListItemMetadataEntry =
30→  | {
31→      type: 'label';
32→      title: string;
33→      text?: string;
34→    }
35→  | {
36→      type: 'link';
37→      title: string;
38→      text: string;
39→      target: string;
40→    }
41→  | {
42→      type: 'tag-list';
43→      title: string;
44→      tags: {
45→        text: string;
46→        color?: TagColor;
47→      }[];
48→    }
49→  | { type: 'separator' };
50→
51→export interface SectionData {
52→  title: string;
53→  items: ListItemData[];
54→}
55→
56→export interface GridItemData {
57→  id: string;
58→  title: string;
59→  subtitle?: string;
60→  icon?: ReactNode;
61→}
62→
63→export type ColorCategory = 'warm' | 'cool' | 'neutral';
64→
65→export interface ColorItemData extends GridItemData {
