 95→function truncateContent(content: string, maxLength: number): string {
 96→  const singleLine = content.replace(/\n/g, ' ');
 97→  if (singleLine.length <= maxLength) return singleLine;
 98→  return singleLine.slice(0, maxLength) + '\u2026';
 99→}
