371→    }
372→    if (!ftsResults && query) {
373→      items = items.filter(
374→        e =>
375→          fuzzyMatch(query, e.name) ||
376→          fuzzyMatch(query, e.keyword) ||
377→          fuzzyMatch(query, e.content),
378→      );
379→    }
380→    return items;
381→  }, [
382→    entries,
383→    query,
384→    filterValue,
385→    ftsResults,
386→  ]);
387→
388→  const groupedByCategory = useMemo(() => {
389→    const groups: {
390→      title: string;
391→      items: SnippetEntry[];
392→    }[] = [];
393→    const categoryOrder = [
394→      'code',
395→      'email',
396→      'template',
