389→  function getSectionInfo(index: number) {
390→    for (const b of sectionBoundaries) {
391→      if (index >= b.start && index < b.start + b.length) {
392→        return {
393→          sectionStart: b.start,
394→          sectionLength: b.length,
395→        };
396→      }
397→    }
