115→function formatTime(time: string): string {
116→  const parts = time.split(':').map(Number);
117→  const hours = parts[0];
118→  const minutes = parts[1];
119→  if (
120→    hours === undefined ||
121→    isNaN(hours) ||
122→    minutes === undefined ||
123→    isNaN(minutes)
124→  ) {
125→    return time || '--:--';
126→  }
127→  const period = hours >= 12 ? 'PM' : 'AM';
128→  const h = hours % 12 || 12;
129→  return `${h}:${String(minutes).padStart(2, '0')} ${period}`;
130→}
131→
132→function formatDueLabel(dueDate: Date, renderNow: Date): string {
133→  const todayStart = new Date(renderNow);
134→  todayStart.setHours(0, 0, 0, 0);
135→  const dueStart = new Date(dueDate);
136→  dueStart.setHours(0, 0, 0, 0);
137→
138→  const diffDays = Math.round(
139→    (dueStart.getTime() - todayStart.getTime()) / (1000 * 60 * 60 * 24),
140→  );
141→
142→  if (diffDays === 0) return 'Today';
143→  if (diffDays === 1) return 'Tomorrow';
144→  if (diffDays === -1) return 'Yesterday';
145→  if (diffDays < 0) return `${Math.abs(diffDays)} days overdue`;
146→  if (diffDays <= 7) return `In ${diffDays} days`;
147→  return dueDate.toLocaleDateString(undefined, {
148→    month: 'short',
149→    day: 'numeric',
150→  });
151→}
