166→function rowToEntry(row: ReminderRow): ReminderEntry {
167→  const dueDate = new Date(row.due_date);
168→  const completedAt = row.completed_at ? new Date(row.completed_at) : null;
169→  const createdAt = new Date(row.created_at);
170→  return {
171→    id: row.id,
172→    title: row.title,
173→    dueDate: isNaN(dueDate.getTime()) ? new Date() : dueDate,
174→    dueTime: row.due_time,
175→    repeat: isRepeatOption(row.repeat) ? row.repeat : 'none',
176→    notes: row.notes,
177→    completed: row.completed === 1,
178→    completedAt:
179→      completedAt && !isNaN(completedAt.getTime()) ? completedAt : null,
180→    createdAt: isNaN(createdAt.getTime()) ? new Date() : createdAt,
181→  };
182→}
