184→function entryToRow(entry: ReminderEntry): ReminderRow {
185→  return {
186→    id: entry.id,
187→    title: entry.title,
188→    due_date: entry.dueDate.toISOString(),
189→    due_time: entry.dueTime,
190→    repeat: entry.repeat,
191→    notes: entry.notes,
192→    completed: entry.completed ? 1 : 0,
193→    completed_at: entry.completedAt?.toISOString() ?? null,
194→    created_at: entry.createdAt.toISOString(),
195→  };
196→}
